import { createHmac, timingSafeEqual } from "node:crypto";

const port = Number(Bun.env.PORT ?? 3000);
const secret = Bun.env.JWT_SECRET ?? "bun-bench-secret";

function base64urlDecodeToString(segment: string): string | null {
  // base64url alphabet must not contain +, /, or = padding.
  if (!/^[A-Za-z0-9_-]+$/.test(segment)) return null;
  try {
    return Buffer.from(segment, "base64url").toString("utf8");
  } catch {
    return null;
  }
}

function sign(signingInput: string): string {
  return createHmac("sha256", secret).update(signingInput).digest("base64url");
}

function constantTimeEqual(a: string, b: string): boolean {
  const bufA = Buffer.from(a, "utf8");
  const bufB = Buffer.from(b, "utf8");
  if (bufA.length !== bufB.length) return false;
  return timingSafeEqual(bufA, bufB);
}

type VerifyResult =
  | { ok: true; claims: Record<string, unknown> }
  | { ok: false; error: string };

function verify(token: string): VerifyResult {
  const segments = token.split(".");
  if (segments.length !== 3) return { ok: false, error: "malformed" };
  const [headerSeg, payloadSeg, signatureSeg] = segments;
  if (headerSeg.length === 0 || payloadSeg.length === 0) {
    return { ok: false, error: "malformed" };
  }

  const headerJson = base64urlDecodeToString(headerSeg);
  const payloadJson = base64urlDecodeToString(payloadSeg);
  if (headerJson === null || payloadJson === null) {
    return { ok: false, error: "malformed" };
  }

  let header: unknown;
  let payload: unknown;
  try {
    header = JSON.parse(headerJson);
    payload = JSON.parse(payloadJson);
  } catch {
    return { ok: false, error: "malformed" };
  }
  if (typeof header !== "object" || header === null) {
    return { ok: false, error: "malformed" };
  }
  if (typeof payload !== "object" || payload === null) {
    return { ok: false, error: "malformed" };
  }

  // Algorithm pinning — pin to HS256 before any signature handling.
  const alg = (header as Record<string, unknown>).alg;
  if (alg !== "HS256") {
    return { ok: false, error: "invalid_alg" };
  }

  // Signature check (constant-time over the base64url signature strings).
  const expected = sign(`${headerSeg}.${payloadSeg}`);
  if (!constantTimeEqual(signatureSeg, expected)) {
    return { ok: false, error: "invalid_signature" };
  }

  const claims = payload as Record<string, unknown>;

  // Expiry.
  if ("exp" in claims) {
    const exp = claims.exp;
    if (typeof exp !== "number" || !Number.isFinite(exp)) {
      return { ok: false, error: "malformed" };
    }
    const now = Math.floor(Date.now() / 1000);
    if (exp <= now) {
      return { ok: false, error: "expired" };
    }
  }

  // Subject required.
  if (!("sub" in claims) || claims.sub === undefined || claims.sub === null) {
    return { ok: false, error: "malformed" };
  }

  return { ok: true, claims };
}

function extractBearer(header: string | null): string | null {
  if (!header) return null;
  const match = /^Bearer (.+)$/.exec(header.trim());
  if (!match) return null;
  const token = match[1].trim();
  return token.length > 0 ? token : null;
}

Bun.serve({
  port,
  fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/me") {
      const token = extractBearer(request.headers.get("authorization"));
      if (token === null) {
        return Response.json({ error: "missing_token" }, { status: 401 });
      }
      const result = verify(token);
      if (!result.ok) {
        return Response.json({ error: result.error }, { status: 401 });
      }
      return Response.json(result.claims, { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`jwt-verify reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
